+- (void)buttonClicked:(UIButton *)sender {
+    if (sender == self.selectedButton) return;
+    [self setButtonSelected:sender];
+    NSArray *allButtons = @[self.vipButton, self.svipButton, self.benefitButton];
+    for (UIButton *button in allButtons) {
+        if (button != sender) {
+            [self setButtonDeselected:button];
+        }
+    }
+    
+    // 先切换目标类型，再触发商品筛选与刷新，避免使用旧类型筛选
+    if (sender == _vipButton) {
+        _selectedProductType = WBProductTypeVIP;
+        _switchTypeView.image = [UIImage imageNamed:@"switchType_vip"];
+        _privilegeDetailView.hidden = YES;
+    } else if (sender == _svipButton) {
+        _selectedProductType = WBProductTypeSVIP;
+        _switchTypeView.image = [UIImage imageNamed:@"switchType_svip"];
+        _privilegeDetailView.hidden = YES;
+    } else {
+        _switchTypeView.image = [UIImage imageNamed:@"switchType_benefit"];
+        _privilegeDetailView.hidden = NO;
+    }
+    
+    _currentProducts = nil;    // 重置商品数据
+    
+    // 刷新商品列表（将按最新 selectedProductType 重新筛选）
+    self.productCollectionView.products = self.currentProducts;
+    [self refreshData];
+}
+
+- (void)setButtonSelected:(UIButton *)button {
