   869	- (void)removeConsumedPromosFromProductAndAvailablePromos {
   870	    WBProductModel *purchasedProduct = [WBPaymentManager sharedManager].product;
   871	    if (![purchasedProduct.selectedPromoModels count]) return;
   872	    NSMutableArray<WBPromoModel *> *availablePromoModels = [NSMutableArray arrayWithArray:self.availablePromos];
   873	    for (WBPromoModel *consumedPromoModel in purchasedProduct.selectedPromoModels) {
   874	        [self.availablePromos enumerateObjectsUsingBlock:^(WBPromoModel * _Nonnull availablePromoModel, NSUInteger idx, BOOL * _Nonnull stop) {
   875	            if (![availablePromoModel.code isEqualToString:consumedPromoModel.code] || ![availablePromoModels containsObject:availablePromoModel]) {
   876	                NSParameterAssert(idx != [self.availablePromos count] - 1);
   877	                return;
   878	            }
   879	            [availablePromoModels removeObject:availablePromoModel];
   880	            *stop = true;
   881	        }];
   882	    }
   883	    
   884	    for (WBProductModel *product in self.allProducts) {
   885	        product.selectedPromoModels = nil;
   886	    }
   887	    
   888	    self.availablePromos = [availablePromoModels copy];
   889	}
