   949	- (void)ensureFloatingViewHierarchyBeforeRelayout {
   950	    if (!self.isViewLoaded) return;
   951	    
   952	    if (self.floatingView.superview != self.view) {
   953	        [self.floatingView removeFromSuperview];
   954	        [self.view addSubview:self.floatingView];
   955	    }
   956	    if (self.payOptionsView.superview != self.floatingView) {
   957	        [self.payOptionsView removeFromSuperview];
   958	        [self.floatingView addSubview:self.payOptionsView];
   959	    }
   960	    if (self.promoSectionView.superview != self.floatingView) {
   961	        [self.promoSectionView removeFromSuperview];
   962	        [self.floatingView addSubview:self.promoSectionView];
   963	    }
   964	    if (self.purchaseView.superview != self.floatingView) {
   965	        [self.purchaseView removeFromSuperview];
   966	        [self.floatingView addSubview:self.purchaseView];
   967	    }
   968	    
   969	    [self.payOptionsView mas_remakeConstraints:^(MASConstraintMaker *make) {
   970	        make.top.equalTo(self.floatingView).offset(ZOOM(8));
   971	        make.left.right.equalTo(self.view);
   972	        make.height.mas_equalTo(ZOOM(42));
   973	    }];
   974	    
   975	    [self.promoSectionView mas_remakeConstraints:^(MASConstraintMaker *make) {
   976	        make.top.equalTo(self.payOptionsView.mas_bottom).offset(ZOOM(10));
   977	        make.left.equalTo(self.view).offset(ZOOM(16));
   978	        make.right.equalTo(self.view).offset(ZOOM(-16));
   979	        make.height.mas_equalTo(ZOOM(28));
   980	    }];
   981	}
