   301	- (int)calculateAvailablePromosForProduct:(WBProductModel *)product {
   302	    int availablePromoCount = 0;
   303	    for (WBPromoModel *promo in self.availablePromos) {
   304	        // 苹果连续订阅优惠券
   305	        if ([WBVipViewController isAppleSubscription:product]) {
   306	            if ([WBVipViewController isAppleSubscriptionPromo:promo] && promo.minCharge <= [product.price floatValue]) {
   307	                availablePromoCount++;
   308	            }
   309	        }
   310	        // 普通优惠券
   311	        else {
   312	            if (promo.minCharge > [product.price floatValue] || [WBVipViewController isAppleSubscriptionPromo:promo]) continue;
   313	            availablePromoCount++;
   314	        }
   315	    }
   316	    return availablePromoCount;
   317	}
