   794	- (void)removeConsumedPromosFromProductAndAvailablePromos {
   795	    WBProductModel *purchasedProduct = [WBPaymentManager sharedManager].product;
   796	    if (![purchasedProduct.selectedPromoModels count]) return;
   797	    NSMutableArray<WBPromoModel *> *availablePromoModels = [NSMutableArray arrayWithArray:self.availablePromos];
   798	    for (WBPromoModel *consumedPromoModel in purchasedProduct.selectedPromoModels) {
   799	        [self.availablePromos enumerateObjectsUsingBlock:^(WBPromoModel * _Nonnull availablePromoModel, NSUInteger idx, BOOL * _Nonnull stop) {
   800	            if (![availablePromoModel.code isEqualToString:consumedPromoModel.code] || ![availablePromoModels containsObject:availablePromoModel]) {
   801	                NSParameterAssert(idx != [self.availablePromos count] - 1);
   802	                return;
   803	            }
   804	            [availablePromoModels removeObject:availablePromoModel];
   805	            *stop = true;
   806	        }];
   807	    }
   808	    
   809	    for (WBProductModel *product in self.allProducts) {
   810	        product.selectedPromoModels = nil;
   811	    }
   812	    
   813	    self.availablePromos = [availablePromoModels copy];
   814	}
