diff --git a/WeBox/UI/Pages/Vip/View/WBVipPrivilegeView.m b/WeBox/UI/Pages/Vip/View/WBVipPrivilegeView.m
new file mode 100644
index 00000000..3c51c393
--- /dev/null
+++ b/WeBox/UI/Pages/Vip/View/WBVipPrivilegeView.m
@@ -0,0 +1,364 @@
+//
+//  WBVipPrivilegeView.m
+//  WeBox
+//
+//  Created by 蒙俊竹 on 2025/12/16.
+//  Copyright © 2025 Staff004. All rights reserved.
+//
+
+#import "WBVipPrivilegeView.h"
+#import "WBVIPFeatureManager.h"
+#import "WBVIPFeatureModel.h"
+#import "WBGradientLabel.h"
+#import <objc/runtime.h>
+
+static char kFeatureModelKey;
+
+@interface WBVipPrivilegeView ()
+
+@property (nonatomic, strong) UIImageView *titleImageView;
+@property (nonatomic, strong) UIView *containerView;
+@property (nonatomic, strong) UIView *highlightBenefitContainerView;
+@property (nonatomic, strong) UIView *commonBenefitContainerView;
+@property (nonatomic, strong) NSArray<WBVIPFeatureModel*> *features;
+@property (nonatomic, copy) NSString *vipClass;
+@property (nonatomic, strong) WBProductModel *selectedProduct;
+
+@end
+
+@implementation WBVipPrivilegeView
+
+- (instancetype)initWithVIPClass:(NSString *)vipClass selectedProduct:(WBProductModel *)selectedProduct {
+    self = [super init];
+    if (self) {
+        self.vipClass = vipClass;
+        self.selectedProduct = selectedProduct;
+        self.features = [WBVIPFeatureManager.sharedManager getFeatures];
+        [self setupUI];
+    }
+    return self;
+}
+
+
+#pragma mark - setUpUI
+
+- (void)setupUI {
+    self.backgroundColor = [UIColor clearColor];
+    [self addSubviews];
+    [self addAllConstraints];
+    [self createBenefitViewsWithFeatures:self.features];
+}
+
+- (void)addSubviews {
+    [self addSubview:self.titleImageView];
+    [self addSubview:self.containerView];
+    [self.containerView addSubview:self.highlightBenefitContainerView];
+    [self.containerView addSubview:self.commonBenefitContainerView];
+}
+
+- (void)addAllConstraints {
+    [_titleImageView mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.left.top.equalTo(self);
+        make.width.mas_equalTo(ZOOM(81));
+        make.height.mas_equalTo(ZOOM(17));
+    }];
+    
+    [_containerView mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.top.equalTo(self.titleImageView.mas_bottom).offset(ZOOM(12));
+        make.left.right.bottom.equalTo(self);
+    }];
+    
+    [_highlightBenefitContainerView mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.left.equalTo(self.containerView).offset(ZOOM(10));
+        make.right.equalTo(self.containerView).offset(ZOOM(-10));
+        make.top.equalTo(self.containerView).offset(ZOOM(10));
+        make.height.mas_equalTo(ZOOM(96));
+    }];
+    
+    [_commonBenefitContainerView mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.left.equalTo(self.containerView).offset(ZOOM(10));
+        make.right.equalTo(self.containerView).offset(ZOOM(-10));
+        make.bottom.equalTo(self.containerView).offset(ZOOM(-10));
+        make.height.mas_equalTo(ZOOM(44));
+    }];
+}
+
+
+#pragma mark - Update UI
+
+- (void)updateUIWithVipClass:(NSString *)vipClass selectedProduct:(WBProductModel *)selectedProduct {
+    self.vipClass = vipClass;
+    self.selectedProduct = selectedProduct;
+    [self updateBenefitViewInContainer:self.highlightBenefitContainerView];
+    [self updateBenefitViewInContainer:self.commonBenefitContainerView];
+}
+
+- (void)updateBenefitViewInContainer:(UIView *)containerView {
+    for (UIView *benefitView in containerView.subviews) {
+        WBVIPFeatureModel *feature = objc_getAssociatedObject(benefitView, &kFeatureModelKey);
+        BOOL hasBenefit = [self selectedProductHasBenefitForFeature:feature];
+        
+        UIImageView *svipImageView = [benefitView viewWithTag:1004];
+        if ([svipImageView isKindOfClass:[UIImageView class]]) {
+            NSString *imageName = hasBenefit ? @"privilegeSVIPLabelImage_enable" : @"privilegeSVIPLabelImage_disable";
+            svipImageView.image = [UIImage imageNamed:imageName];
+        }
+        
+        UIImageView *iconImageView = [benefitView viewWithTag:1001];
+        if (iconImageView && [iconImageView isKindOfClass:[UIImageView class]] && !svipImageView.hidden) {
+            NSString *imageName = hasBenefit ? feature.icon_v1_svip : feature.icon_v1;
+            iconImageView.image = [UIImage imageNamed:imageName];
+        }
+        
+        WBGradientLabel *highlightNameLabel = [benefitView viewWithTag:1002];
+        if ([highlightNameLabel isKindOfClass:[WBGradientLabel class]] && !svipImageView.hidden) {
+            if (hasBenefit) {
+                highlightNameLabel.colors = [self colorsForHighlightFeature:feature];
+            } else {
+                highlightNameLabel.colors = @[(id)WBColorHex(0xBBBBBB).CGColor, (id)WBColorHex(0xBBBBBB).CGColor];
+            }
+        }
+        
+        UILabel *descLabel = [benefitView viewWithTag:1003];
+        if (descLabel && [descLabel isKindOfClass:[UILabel class]] && !svipImageView.hidden) {
+            descLabel.textColor = hasBenefit ? WBColorHex(0x666666) : WBColorHex(0xBBBBBB);
+        }
+        
+        WBGradientLabel *commonNameLabel = [benefitView viewWithTag:1005];
+        if ([commonNameLabel isKindOfClass:[WBGradientLabel class]] && !svipImageView.hidden) {
+            if (hasBenefit) {
+                commonNameLabel.colors = [self colorsForCommonFeature:feature];
+            } else {
+                commonNameLabel.colors = @[(id)WBColorHex(0xBBBBBB).CGColor, (id)WBColorHex(0xBBBBBB).CGColor];
+            }
+        }
+    }
+}
+
+- (BOOL)selectedProductHasBenefitForFeature:(WBVIPFeatureModel *)feature {
+    if (!feature) return NO;
+    NSUInteger bit = (NSUInteger)[feature.bit integerValue];
+    if (bit == 0 || !self.selectedProduct) return NO;
+
+    // 特殊规则：VIP商品（非SVIP）下，广告全免始终置灰。
+    if ([feature.code_name isEqualToString:@"adsfree"] &&
+        (self.selectedProduct.typeFlags & WBProductTypeFlagVIPLevel) == 0) {
+        return NO;
+    }
+
+    return (self.selectedProduct.benefit & bit) != 0;
+}
+
+- (NSArray *)colorsForHighlightFeature:(WBVIPFeatureModel *)feature {
+    if ([feature.code_name isEqualToString:@"pretense"]) {
+        return @[(id)WBColorHex(0x9A67FF).CGColor, (id)WBColorHex(0x4063E7).CGColor];
+    }
+    return @[(id)WBColorHex(0x333333).CGColor, (id)WBColorHex(0x333333).CGColor];
+}
+
+- (NSArray *)colorsForCommonFeature:(WBVIPFeatureModel *)feature {
+    if ([feature.code_name isEqualToString:@"oneclick"] || [feature.code_name isEqualToString:@"adsfree"]) {
+        return @[(id)WBColorHex(0x9A67FF).CGColor, (id)WBColorHex(0x4063E7).CGColor];
+    }
+    return @[(id)WBColorHex(0x4746CA).CGColor, (id)WBColorHex(0x4746CA).CGColor];
+}
+
+
+#pragma mark - Benefit View
+
+- (void)createBenefitViewsWithFeatures:(NSArray<WBVIPFeatureModel*> *)features {
+    NSArray *highlightFeatureCodes = @[@"pretense", @"disguise", @"lock"];
+    NSArray *commonFeatureCodes = @[@"infinite", @"notification", @"oneclick", @"adsfree"];
+    
+    // 筛选出高亮特权的模型
+    NSMutableArray *highlightFeatures = [NSMutableArray array];
+    for (NSString *code in highlightFeatureCodes) {
+        NSPredicate *predicate = [NSPredicate predicateWithFormat:@"code_name == %@", code];
+        NSArray *filteredArray = [features filteredArrayUsingPredicate:predicate];
+        if (filteredArray.count > 0) {
+            [highlightFeatures addObject:filteredArray.firstObject];
+        }
+    }
+    
+    // 筛选出普通特权的模型
+    NSMutableArray *commonFeatures = [NSMutableArray array];
+    for (NSString *code in commonFeatureCodes) {
+        NSPredicate *predicate = [NSPredicate predicateWithFormat:@"code_name == %@", code];
+        NSArray *filteredArray = [features filteredArrayUsingPredicate:predicate];
+        if (filteredArray.count > 0) {
+            [commonFeatures addObject:filteredArray.firstObject];
+        }
+    }
+    
+    // 创建高亮特权视图
+    NSMutableArray *highlightViews = [NSMutableArray array];
+    for (WBVIPFeatureModel *feature in highlightFeatures) {
+        UIView *benefitView = [self createhighlightBenefitContainerViewWithFeatureModel:feature];
+        [self.highlightBenefitContainerView addSubview:benefitView];
+        [highlightViews addObject:benefitView];
+    }
+    
+    // 等高亮特权视图布局
+    if (highlightViews.count > 0) {
+        [highlightViews mas_distributeViewsAlongAxis:MASAxisTypeHorizontal
+                                   withFixedSpacing:ZOOM(10)
+                                        leadSpacing:ZOOM(0)
+                                        tailSpacing:ZOOM(0)];
+        
+        [highlightViews mas_makeConstraints:^(MASConstraintMaker *make) {
+            make.top.equalTo(self.highlightBenefitContainerView).offset(ZOOM(8));
+            make.bottom.equalTo(self.highlightBenefitContainerView).offset(ZOOM(-8));
+        }];
+    }
+    
+    // 创建普通特权视图
+    NSMutableArray *commonViews = [NSMutableArray array];
+    for (WBVIPFeatureModel *feature in commonFeatures) {
+        UIView *benefitView = [self createcommonBenefitContainerViewWithFeatureModel:feature];
+        [self.commonBenefitContainerView addSubview:benefitView];
+        [commonViews addObject:benefitView];
+    }
+    
+    // 等普通特权视图布局
+    if (commonViews.count > 0) {
+        [commonViews mas_distributeViewsAlongAxis:MASAxisTypeHorizontal
+                                 withFixedSpacing:ZOOM(8)
+                                      leadSpacing:ZOOM(0)
+                                      tailSpacing:ZOOM(0)];
+        
+        [commonViews mas_makeConstraints:^(MASConstraintMaker *make) {
+            make.bottom.equalTo(self.commonBenefitContainerView).offset(ZOOM(-8));
+            make.height.mas_equalTo(ZOOM(44));
+        }];
+    }
+}
+
+- (UIView *)createhighlightBenefitContainerViewWithFeatureModel:(WBVIPFeatureModel *)feature {
+    BOOL hasBenefit = [self selectedProductHasBenefitForFeature:feature];
+    UIView *highlightBenefitContainerView = [[UIView alloc] init];
+    objc_setAssociatedObject(highlightBenefitContainerView, &kFeatureModelKey, feature, OBJC_ASSOCIATION_RETAIN_NONATOMIC);
+    highlightBenefitContainerView.backgroundColor = WBColorHex(0xFFFFFF);
+    
+    NSString *highlightIcon = hasBenefit ? feature.icon_v1_svip : feature.icon_v1;
+    UIImageView *iconImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:highlightIcon]];
+    iconImageView.layer.cornerRadius = ZOOM(14);
+    iconImageView.clipsToBounds = YES;
+    iconImageView.tag = 1001;   // 标识icon
+    [highlightBenefitContainerView addSubview:iconImageView];
+    [iconImageView mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.centerX.equalTo(highlightBenefitContainerView);
+        make.top.equalTo(highlightBenefitContainerView);
+        make.width.height.mas_equalTo(ZOOM(28));
+    }];
+    
+    WBGradientLabel *nameLabel = [[WBGradientLabel alloc] initWithDirection:WBGradientDirectionTopToBottom];
+    nameLabel.text = feature.name_svip;
+    nameLabel.colors = hasBenefit ? [self colorsForHighlightFeature:feature] : @[(id)WBColorHex(0xBBBBBB).CGColor, (id)WBColorHex(0xBBBBBB).CGColor];
+    nameLabel.font = [UIFont systemFontOfSize:ZOOM(16) weight:UIFontWeightSemibold];
+    nameLabel.tag = 1002;
+    [highlightBenefitContainerView addSubview:nameLabel];
+    [nameLabel mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.top.equalTo(iconImageView.mas_bottom).offset(ZOOM(8));
+        make.centerX.equalTo(highlightBenefitContainerView);
+    }];
+    
+    UILabel *descLabel = [[UILabel alloc] init];
+    if ([feature.code_name isEqualToString:@"pretense"]) {
+        descLabel.text = @"变身为AI工具";
+    } else if ([feature.code_name isEqualToString:@"disguise"]) {
+        descLabel.text = @"更换图标/名称";
+    } else {
+        descLabel.text = @"添加专属密码";
+    }
+    descLabel.textColor = hasBenefit ? WBColorHex(0x666666) : WBColorHex(0xBBBBBB);
+    descLabel.font = [UIFont systemFontOfSize:ZOOM(14) weight:UIFontWeightRegular];
+    descLabel.tag = 1003;
+    [highlightBenefitContainerView addSubview:descLabel];
+    [descLabel mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.top.equalTo(nameLabel.mas_bottom).offset(ZOOM(4));
+        make.centerX.equalTo(highlightBenefitContainerView);
+    }];
+    
+    NSString *imageName = hasBenefit ? @"privilegeSVIPLabelImage_enable" : @"privilegeSVIPLabelImage_disable";
+    UIImageView *svipImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:imageName]];
+    svipImageView.tag = 1004;   // 标识SVIP标签
+    [highlightBenefitContainerView addSubview:svipImageView];
+    [svipImageView mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.top.equalTo(highlightBenefitContainerView).offset(ZOOM(-8));
+        make.right.equalTo(highlightBenefitContainerView);
+        make.width.mas_equalTo(ZOOM(31));
+        make.height.mas_equalTo(ZOOM(14));
+    }];
+    svipImageView.hidden = [feature.code_name isEqualToString:@"pretense"] ? NO : YES;
+
+    return highlightBenefitContainerView;
+}
+
+- (UIView *)createcommonBenefitContainerViewWithFeatureModel:(WBVIPFeatureModel *)feature {
+    BOOL hasBenefit = [self selectedProductHasBenefitForFeature:feature];
+    UIView *commonBenefitContainerView = [[UIView alloc] init];
+    objc_setAssociatedObject(commonBenefitContainerView, &kFeatureModelKey, feature, OBJC_ASSOCIATION_RETAIN_NONATOMIC);
+    commonBenefitContainerView.backgroundColor = WBColorHex(0xF8F8F8);
+    commonBenefitContainerView.layer.cornerRadius = ZOOM(8);
+    
+    WBGradientLabel *nameLabel = [[WBGradientLabel alloc] initWithDirection:WBGradientDirectionTopToBottom];
+    nameLabel.text = feature.name_svip;
+    nameLabel.textColor = hasBenefit ? WBColorHex(0x4746CA) : WBColorHex(0xBBBBBB);
+    nameLabel.colors = hasBenefit ? [self colorsForCommonFeature:feature] : @[(id)WBColorHex(0xBBBBBB).CGColor, (id)WBColorHex(0xBBBBBB).CGColor];
+    nameLabel.font = ([feature.code_name isEqualToString:@"oneclick"] || [feature.code_name isEqualToString:@"adsfree"]) ? [UIFont systemFontOfSize:ZOOM(14) weight:UIFontWeightMedium] : [UIFont systemFontOfSize:ZOOM(14) weight:UIFontWeightRegular];
+    nameLabel.tag = 1005;
+    [commonBenefitContainerView addSubview:nameLabel];
+    [nameLabel mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.center.equalTo(commonBenefitContainerView);
+    }];
+    
+    NSString *imageName = hasBenefit ? @"privilegeSVIPLabelImage_enable" : @"privilegeSVIPLabelImage_disable";
